async function onMoveWithinFolder(source: 'global' | 'character', scriptId: string): Promise<void> {
  try {
    // 简化：使用文本输入作为临时选择器（V2 后续可替换为选择器弹窗）
    const { usePopups } = await import('../composables/usePopups');
